import org.junit.jupiter.api.Test

class CommentWrappingIssueTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a single line block containing a block comment then do not wrap this comment to a multiline block`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a single line block containing a multiple block comments then do not wrap this comment to a multiline block`() {
        val code =
            """
            val foo = { /* no-op */ /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code)
            .hasNoLintViolations()
    }
}
